function summarizeProcessingFromWorkLogEntry(
  entry: WorkLogEntry | null,
): { title: string; detail: string } | null {
  if (!entry) {
    return null;
  }

  const label = truncate(entry.command ?? entry.toolTitle ?? entry.label, 88);
  switch (entry.itemType) {
    case "command_execution":
      return {
        title: "Pi running command",
        detail: label,
      };
    case "file_change":
      return {
        title: "Pi editing files",
        detail: label,
      };
    case "mcp_tool_call":
      return {
        title: "Pi inspecting repo",
        detail: label,
      };
    case "web_search":
      return {
        title: "Pi searching web",
        detail: label,
      };
    case "image_view":
      return {
        title: "Pi inspecting image",
        detail: label,
      };
    default:
      break;
  }

  if (entry.requestKind === "command") {
    return {
      title: "Pi waiting for command approval",
      detail: label,
    };
  }
  if (entry.requestKind === "file-change") {
    return {
      title: "Pi waiting for file-change approval",
      detail: label,
    };
  }
  if (entry.requestKind === "file-read") {
    return {
      title: "Pi waiting for file-read approval",
      detail: label,
    };
  }
  if (entry.tone === "thinking") {
    return {
      title: "Pi reasoning",
      detail: label,
    };
  }

  return {
    title: "Pi working",
    detail: label,
  };
}

